// Format Slack message for ranking alerts
const data = $input.first().json;
const { categorized, counts } = data;

if (counts.total === 0) {
  return [{ json: { skip: true } }];
}

const today = new Date().toISOString().split('T')[0];
let message = `:chart_with_upwards_trend: *Ranking Changes for ${today}*\n`;

// Critical changes
if (categorized.critical.length > 0) {
  message += `\n:red_circle: *Critical* (${categorized.critical.length})\n`;
  categorized.critical.slice(0, 5).forEach(c => {
    if (c.change_type === 'lost_ranking') {
      message += `• "${c.keyword}" - *Lost ranking* (was #${c.yesterday_position})\n`;
    } else {
      message += `• "${c.keyword}" - #${c.yesterday_position} → #${c.today_position} (${c.position_change > 0 ? '+' : ''}${c.position_change})\n`;
    }
  });
  if (categorized.critical.length > 5) {
    message += `  _...and ${categorized.critical.length - 5} more_\n`;
  }
}

// Warning changes
if (categorized.warning.length > 0) {
  message += `\n:large_yellow_circle: *Warning* (${categorized.warning.length})\n`;
  categorized.warning.slice(0, 5).forEach(c => {
    message += `• "${c.keyword}" - #${c.yesterday_position} → #${c.today_position} (${c.position_change > 0 ? '+' : ''}${c.position_change})\n`;
  });
  if (categorized.warning.length > 5) {
    message += `  _...and ${categorized.warning.length - 5} more_\n`;
  }
}

// Info (gains) - brief summary
if (categorized.info.length > 0) {
  message += `\n:large_green_circle: *Gains* (${categorized.info.length})\n`;
  categorized.info.slice(0, 3).forEach(c => {
    if (c.change_type === 'new_ranking') {
      message += `• "${c.keyword}" - *New ranking* at #${c.today_position}\n`;
    } else {
      message += `• "${c.keyword}" - #${c.yesterday_position} → #${c.today_position}\n`;
    }
  });
  if (categorized.info.length > 3) {
    message += `  _...and ${categorized.info.length - 3} more gains_\n`;
  }
}

return [{
  json: {
    message,
    counts,
    skip: false
  }
}];
